创建codeShrink.js文件，写入下面代码:
// 代码块收缩$(function () &#123; var $code_expand = $(&#x27;&lt;i class=&quot;fa fa-chevron-down code-expand&quot; title=&quot;折叠代码&quot; aria-hidden=&quot;true&quot;&gt;&lt;/i&gt;&#x27;); $(&#x27;.code-area&#x27;).prepend($code_expand); $(&#x27;.code-expand&#x27;).on(&#x27;click&#x27;, function () &#123; if ($(this).parent().hasClass(&#x27;code-closed&#x27;)) &#123; $(this).siblings(&#x27;pre&#x27;).find(&#x27;code&#x27;).show(); $(this).parent().removeClass(&#x27;code-closed&#x27;); &#125; else &#123; $(this).siblings(&#x27;pre&#x27;).find(&#x27;code&#x27;).hide(); $(this).parent().addClass(&#x27;code-closed&#x27;); &#125; &#125;);&#125;); 之后在themes/matery/source/css/matery.css中添加下面代码: code &#123; padding: 1px 5px; font-family: Inconsolata, Monaco, Consolas, &#x27;Courier New&#x27;, Courier, monospace; /* font-size: 0.91rem; */ color: #e96900; background-color: #f8f8f8; border-radius: 2px;&#125;pre code &#123; padding: 0; color: #e8eaf6; background-color: #272822;&#125;pre[class*=&quot;language-&quot;] &#123; padding: 1.2em; margin: .5em 0;&#125;code[class*=&quot;language-&quot;],pre[class*=&quot;language-&quot;] &#123; color: #e8eaf6; white-space: pre-wrap !important;&#125; */.line-numbers-rows &#123; border-right-width: 0px !important;&#125;.line-numbers &#123; padding: 1.5rem 1.5rem 1.5rem 3.2rem !important; margin: 1rem 0 !important; background: #272822; overflow: auto; border-radius: 0.35rem; tab-size: 4;&#125;pre &#123; padding: 1.5rem !important; margin: 1rem 0 !important; background: #272822; overflow: auto; border-radius: 0.35rem; tab-size: 4;&#125;pre::before &#123; content: &quot;&quot;; height: 16px; margin-bottom: 0; display: block;&#125;pre::after &#123; content: &quot; &quot;; position: absolute; border-radius: 50%; background: #ff5f56; width: 12px; height: 12px; top: 0; left: 12px; margin-top: 12px; -webkit-box-shadow: 20px 0 #ffbd2e, 40px 0 #27c93f; box-shadow: 20px 0 #ffbd2e, 40px 0 #27c93f;&#125;code &#123; padding: 1px 5px; font-family: Inconsolata, Monaco, Consolas, &#x27;Courier New&#x27;, Courier, monospace; font-size: 0.91rem; color: #e96900; background-color: #f8f8f8; border-radius: 2px;&#125;.code_copy &#123; position: absolute; top: 0.7rem; right: 35px; z-index: 1; filter: invert(50%); cursor: pointer;&#125;.code_lang &#123; position: absolute; top: 1.2rem; right: 60px; line-height: 0; font-weight: bold; font-family: normal; z-index: 1; filter: invert(50%); cursor: pointer;&#125; .code-expand &#123; position: absolute; top: 4px; right: 0px; filter: invert(50%); padding: 7px 10px; z-index: 1; cursor: pointer; transition: all .3s; transform: rotate(0deg);&#125;.code-closed .code-expand &#123; transform: rotate(-180deg) !important; transition: all .3s;&#125;.code-closed pre::before &#123; height: 0px;&#125;pre code &#123; padding: 0; color: #e8eaf6; background-color: #272822;&#125;pre[class*=&quot;language-&quot;] &#123; padding: 1.2em; margin: .5em 0;&#125;code[class*=&quot;language-&quot;],pre[class*=&quot;language-&quot;] &#123; color: #e8eaf6; white-space: pre-wrap !important;&#125; 最后在themes/matery/layout/post.ejs中添加下面代码: &lt;script type=&quot;text/javascript&quot; src=&quot;/libs/codeBlock/codeBlockFuction.js&quot;&gt;&lt;/script&gt;&lt;!-- 代码语言 --&gt;&lt;script type=&quot;text/javascript&quot; src=&quot;/libs/codeBlock/codeLang.js&quot;&gt;&lt;/script&gt;&lt;!-- 代码块复制 --&gt;&lt;script type=&quot;text/javascript&quot; src=&quot;/libs/codeBlock/codeCopy.js&quot;&gt;&lt;/script&gt;&lt;script type=&quot;text/javascript&quot; src=&quot;/libs/codeBlock/clipboard.min.js&quot;&gt;&lt;/script&gt;&lt;!-- 代码块收缩 --&gt;&lt;script type=&quot;text/javascript&quot; src=&quot;/libs/codeBlock/codeShrink.js&quot;&gt;&lt;/script&gt; &lt;!-- 代码块折行 --&gt;&lt;style type=&quot;text/css&quot;&gt;code[class*=&quot;language-&quot;], pre[class*=&quot;language-&quot;] &#123; white-space: pre !important; &#125;&lt;/style&gt; 最后hexo三连即可
